final:
module RefModule(
  input reset,
  input clk,
  input in,
  output out
);reg out_reg;
  wire _tap_reset = reset & {1{1'b1}};


  always @(posedge clk or negedge reset) begin
    if (!reset) begin
      out_reg <= 0;
    end else begin
      out_reg <= in;
    end
  end

  assign out = out_reg;

endmodule
